const rows = $input.all().map(item => item.json);
const jobs = rows.filter(r => r.job_title);

if (jobs.length === 0) return [];

function esc(text) {
  return (text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const today = new Date().toLocaleDateString('de-DE', {
  timeZone: 'Europe/Berlin',
  day: '2-digit', month: '2-digit', year: 'numeric'
});

const high = jobs.filter(j => j.relevance_score >= 80);
const mid  = jobs.filter(j => j.relevance_score >= 50 && j.relevance_score < 80);
const low  = jobs.filter(j => j.relevance_score < 50);

const lines = [
  `\u{1F4CA} <b>JobRadar \u2014 ${today}</b>`,
  `<i>${jobs.length} ${jobs.length === 1 ? 'вакансия' : 'вакансий'} за 24ч</i>`,
  ''
];

// HIGH tier — full details
if (high.length > 0) {
  lines.push('\u{1F525} <b>Высокая совместимость</b>');
  const medals = ['\u{1F947}','\u{1F948}','\u{1F949}','4\uFE0F\u20E3','5\uFE0F\u20E3','6\uFE0F\u20E3','7\uFE0F\u20E3','8\uFE0F\u20E3','9\uFE0F\u20E3','\u{1F51F}'];
  high.forEach((job, i) => {
    const medal = medals[i] || `${i + 1}.`;
    const location = job.location ? ` | \u{1F4CD} ${esc(job.location)}` : '';
    const wm = job.work_mode ? ` (${esc(job.work_mode)})` : '';
    const summary = job.summary
      ? esc(job.summary).substring(0, 120) + (job.summary.length > 120 ? '\u2026' : '')
      : '';
    lines.push(`${medal} <b>${esc(job.job_title)}</b>`);
    lines.push(`   \u{1F3E2} ${esc(job.company_name)}${location}${wm}`);
    lines.push(`   \u2B50 <b>${job.relevance_score}/100</b>`);
    if (summary) lines.push(`   \u{1F4AC} <i>${summary}</i>`);
    if (job.source_url) lines.push(`   \u{1F517} <a href="${esc(job.source_url)}">Открыть</a>`);
    lines.push('');
  });
}

// MID tier — brief
if (mid.length > 0) {
  lines.push('\u2B50 <b>Средняя совместимость</b>');
  mid.forEach(job => {
    const link = job.source_url ? ` \u2014 <a href="${esc(job.source_url)}">\u{1F517}</a>` : '';
    lines.push(`\u2022 <b>${esc(job.job_title)}</b> @ ${esc(job.company_name)} [${job.relevance_score}]${link}`);
  });
  lines.push('');
}

// LOW tier — list only
if (low.length > 0) {
  lines.push('\u{1F4CB} <b>Низкая совместимость</b>');
  low.forEach(job => {
    const link = job.source_url ? ` <a href="${esc(job.source_url)}">\u{1F517}</a>` : '';
    lines.push(`\u2022 ${esc(job.job_title)} @ ${esc(job.company_name)}${link}`);
  });
}

return [{ json: { text: lines.join('\n') } }];
